import{_ as r,i as d,g as o,e as t,o as l,c,f as a}from"./index-6aff7af6.js";import{P as h,a as p,b as u}from"./ProjectInfo-1b4b0650.js";const m="/assets/hsi-map-demo-9611ca39.png",g="/assets/hsi-demo-1-0593962d.png",w={name:"his-project",components:{ProjectHeader:h,ProjectGallery:p,ProjectInfo:u},data:()=>({singleProjectHeader:{singleProjectTitle:"DB Management Tool",singleProjectDate:"2018-2022",singleProjectTag:"Back end / API Design"},projectImages:[{id:1,title:"HighSpeedInternet Hero",img:d},{id:2,title:"HighSpeedInternet Map",img:m},{id:3,title:"HighSpeedInternet demo",img:g}],projectInfo:{clientHeading:"About Client",companyInfos:[{id:1,title:"Name",details:"Clearlink LLC"},{id:2,title:"Services",details:"Back end development and API design"},{id:3,title:"Website",details:"https://www.highspeedinternet.com/"},{id:4,title:"Phone",details:"801-424-0018"}],objectivesHeading:"Objective",objectivesDetails:"Decouple from existing monolithic service and built a microservice to service that functionality.Also, create a front end DB management tool to allow our data team to easily update availability information.",technologies:[{title:"Tools & Technologies",techs:["HTML","CSS","JavaScript","Vue.js","REST","AWS","Laravel","Docker"]}],projectDetailsHeading:"Challenge",projectDetails:[{id:1,details:'The functionality was built into an in-house lead data system that never saw widespread adoption in the company, so when we decided to deprecate that massive dead tool, we needed to break out the "chunks" that people were using into their own microservices. So the first major challenge was decoupling.Laravel was a simple choice, the existing "monolith" was a laravel project, and seeing how data managementwas the second big ask, it just made sense.'},{id:2,details:`After the initial pain of "drag-droppping" was sorted out, wiring up the functionality was as simple as recreating all of the "laravel" stuff using mainly artisan commands. Models, migrations, views and the like. The spaghetti showed up in tables.  To be fair, it wasn't a simple data problem, but let me try and express it.  Given a zip code, we want to know what internet providers are available, whatspeeds they offer, what technology is being used, what percentage of the zip code is covered, and a few other marketing tags and things. Simple enough at the surface, but notice something.  If you enter your email on the page, you are routed to a specific page for your city and state. Now, if you have ever worked deeply with census block data or zip codes, you will start to notice a lot of edge cases all over the place where zip codes fall into multiple cities, sometime states. So, if you have a zip code that fallsin 2 different cities, what page do we take you too? Well...lets go ahead and just use a weighted value.0-1 indicating "how much" that zip code is in one city vs the other.  It became very complex very quickly`},{id:3,details:`The other major issue, was how long it took to update that "availability" information. The old process requiredthe data team to submit a ticket into our team (Marketing Technology, Martech) containing a CSV of the updated data. We had built an artisan command a LONG time ago to take care of it, and it was one of those"Just run it, it should work as long as they formatted the csv right" things.  It wasn't great.  Turnoverwas 2-4 weeks (1-2 sprints), so our data was always a month behind.  You'd be surprised how often thatdata changes. We were losing out on valuable partnerships because of how "slow and out of date", our datawas, so this became a priority.`},{id:4,details:"In the end, the ability to update the data themselves resulted in dozens of new partnerships, leading to hundreds of thousands of dollars in revenue. The tool was built mainly using Laravel nova and even includeda deployment process so they could push to both their staging and production environments. I was reluctantto give that kind of power to a front end tool, so to make myself feel better about it, I designed a process to enforce a deploy to staging first, so they could log into their staging environment and verify thatthe cards on the front end were actually showing the updated values before pushing to production. Thena LOT of back end validation and transactions to ensure a happy death if anything goes wrong, and cleanrollbacks to ensure no potential downtime rolling back."}],socialSharingsHeading:"Share This",socialSharings:[{id:1,name:"Twitter",icon:"twitter",url:"https://twitter.com"},{id:2,name:"Instagram",icon:"instagram",url:"https://www.instagram.com/hession_sessions/"},{id:3,name:"Facebook",icon:"facebook",url:"https://facebook.com/"},{id:4,name:"LinkedIn",icon:"linkedin",url:"https://www.instagram.com/hession_sessions/"},{id:5,name:"Youtube",icon:"youtube",url:"https://www.youtube.com/"}]}}),mounted(){o.replace()},updated(){o.replace()},methods:{}},f={class:"container mx-auto mt-10 sm:mt-20"};function v(e,y,b,j,k,I){const i=t("ProjectHeader"),n=t("ProjectGallery"),s=t("ProjectInfo");return l(),c("div",f,[a(i,{singleProjectHeader:e.singleProjectHeader},null,8,["singleProjectHeader"]),a(n,{projectImages:e.projectImages},null,8,["projectImages"]),a(s,{projectInfo:e.projectInfo},null,8,["projectInfo"])])}const H=r(w,[["render",v]]);export{H as default};
